#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    int dp[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 0; i < n; i++) {
        dp[i][i] = arr[i];
    }
    for (int len = 2; len <= n; len++) {
        for (int i = 0; i <= n - len; i++) {
            int j = i + len - 1;
            dp[i][j] = dp[i][j - 1] + arr[j];
        }
    }
    int min = dp[0][n - 1];
    for (int i = 1; i < n; i++) {
        if (dp[i][n - 1] < min) {
            min = dp[i][n - 1];
        }
    }
    printf("%d\n", min);
    return 0;
}

